class Grade {
public:
  std::string subject;
  double score;

  Grade(const std::string& subject, double score)
    : subject(subject), score(score) {}
};

class Student {
public:
  std::string name;
  int age;
  std::vector<Grade> grades;

  Student(std::string name, int age) : name(name), age(age) {}

  void addGrade(const std::string& subject, double score) {
    grades.emplace_back(subject, score);
  }

  double calculateAverageGrade() const {
    double total = 0;
    for (const auto& grade : grades) {
      total += grade.score;
    }
    return grades.empty() ? 0 : total / grades.size();
  }

  void displayGrades() const {
    std::cout << name << "'s Grades:\n";
    for (const auto& grade : grades) {
      std::cout << grade.subject << ": " << grade.score << "\n";
    }
    std::cout << "Average: " << calculateAverageGrade() << "\n";
  }
};

