#include <stdio.h>
#include <string.h>
#include <stdbool.h>

void removeDuplicates(char *str) {
  int length = strlen(str);
  bool seen[256] = {false};
  int index = 0;
  for (int i = 0; i < length; i++) {
    if (!seen[(unsigned char)str[i]]) {
      seen[(unsigned char)str[i]] = true;
      str[index++] = str[i];
    }
  }
  str[index] = '\0';
}

int main() {
  char str[] = "aabbccddeeff";
  removeDuplicates(str);
  printf("String with duplicates removed: %s\n", str);
  return 0;
