def make_divisors(n):
  if n==1:
    divisors=[1]
    return divisors
  else:
    divisors=[]
    for i in range(1,n):
      if i*i>n:
        break
      if n%i==0:
        divisors.append(i)
        if i!=n//i:
          divisors.append(n//i)

    divisors.sort(reverse=True)
    return divisors

