public class Parallelogramme {
  public static double[] calculerParallelogramme(double base, double hauteur, double cote) {
    // Calcul de l'aire
    double aire = base * hauteur;

    // Calcul du périmètre
    double perimetre = 2 * (base + cote);

    return new double[] { aire, perimetre };
  }

  public static void main(String[] args) {
    Scanner scanner = new Scanner(System.in);

    // Saisie des dimensions
    System.out.print("Entrez la longueur de la base du parallélogramme : ");
    double base = scanner.nextDouble();
    System.out.print("Entrez la hauteur du parallélogramme : ");
    double hauteur = scanner.nextDouble();
    System.out.print("Entrez la longueur du côté du parallélogramme : ");
    double cote = scanner.nextDouble();

    double[] resultats = calculerParallelogramme(base, hauteur, cote);
    double aire = resultats[0];
    double perimetre = resultats[1];

    System.out.printf("Aire du parallélogramme : %.2f\n", aire);
    System.out.printf("Périmètre du parallélogramme : %.2f\n", perimetre);

    scanner.close();
  }
