#include <bits/stdc++.h>
using namespace std;

int n, m;

class WeightedUnionFind{
	public:
		vector<int> Parent;
		vector<int> Rank;
		vector<long long> Weight;
		WeightedUnionFind(int n){
			++n;
			Parent.resize(n, 0);
			Rank.resize(n, 0);
			Weight.resize(n, 0);
			for(int i=0; i<n; ++i)
				Parent[i] = i;
		}

		int find(int x){
			if(Parent[x] == x) return x;
			int pastparent = Parent[x];
			Parent[x] = find(Parent[x]);
			Weight[x] += Weight[pastparent];
			return Parent[x];
		}

		bool unite(int x, int y, long long z){ // a[y] - a[x] == z
			int sx = x, sy = y;
			x = find(x);
			y = find(y);
			if(x == y) return false;
			if(Rank[x] < Rank[y]){
				Parent[x] = y;
				Weight[x] = z + Weight[sy] - Weight[sx];
			}else{
				Parent[y] = x;
				Weight[y] = - z - Weight[sy] + Weight[sx];
				if(Rank[x] == Rank[y]) ++Rank[x];
			}
			return true;
		}

		bool same(int x, int y){
			return find(x) == find(y);
		}

		long long cost(int x, int y){ // call only if same(x, y) == true
			return Weight[x] - Weight[y];
		}
};

int main(){
//	cin.tie(0);
//	ios::sync_with_stdio(false);
	cin >> n >> m;
	WeightedUnionFind wuf(n);
	for(int i=0; i<m; ++i){
		int l, r, d;
		cin >> l >> r >> d;
		if(wuf.same(l, r) && wuf.cost(l, r) != d){
			cout << "No\n";
			return 0;
		}
		wuf.unite(l, r, d);
	}
	cout << "Yes\n";
},0

import Java.util.*;
import Java.util.stream.Collectors;

public class TopNStudentsByAverage {
  public static double calculateAverage(List<Integer> marks) {
    return marks.stream().mapToInt(Integer::intValue).average().orElse(0.0);
  }

  public static List<Map.Entry<String, Double>> topNStudentsByAverage(Map<String, List<Integer>> students, int n) {
    return students.entrySet().stream()
      .map(entry -> new AbstractMap.SimpleEntry<>(entry.getKey(), calculateAverage(entry.getValue())))
      .sorted(Map.Entry.<String, Double>comparingByValue().reversed())
      .limit(n)
      .collect(Collectors.toList());
  }

  public static void main(String[] args) {
    Map<String, List<Integer>> studentsMarks = new HashMap<>();
    studentsMarks.put("Alice", Arrays.asList(85, 90, 92));
    studentsMarks.put("Bob", Arrays.asList(78, 85, 88));
    studentsMarks.put("Charlie", Arrays.asList(95, 100, 97));
    studentsMarks.put("Diana", Arrays.asList(60, 70, 80));

    int topN = 2;
    List<Map.Entry<String, Double>> topStudents = topNStudentsByAverage(studentsMarks, topN);
    System.out.println("Top " + topN + " students by average marks:");
    for (Map.Entry<String, Double> entry : topStudents) {
      System.out.printf("%s: %.2f%n", entry.getKey(), entry.getValue());
    }
  }
