void addPassenger(PassengerSystem *system, const char *name, const char *passportNumber, int age, const char *destination) {
  if (age < 0) {
    printf("Invalid age.\n");
    return;
  }
  if (system->count < MAX_PASSENGERS) {
    Passenger *p = &system->passengers[system->count++];
    strncpy(p->name, name, NAME_LEN);
    strncpy(p->passportNumber, passportNumber, PASSPORT_LEN);
    p->age = age;
    strncpy(p->destination, destination, DEST_LEN);
    printf("Passenger %s added successfully.\n", name);
  } else {
    printf("Passenger list is full.\n");
  }
}

Passenger* getPassenger(PassengerSystem *system, const char *passportNumber) {
  for (int i = 0; i < system->count; i++) {
    if (strcmp(system->passengers[i].passportNumber, passportNumber) == 0) {
      return &system->passengers[i];
    }
  }
  return NULL;
}

void removePassenger(PassengerSystem *system, const char *passportNumber) {
  for (int i = 0; i < system->count; i++) {
    if (strcmp(system->passengers[i].passportNumber, passportNumber) == 0) {
      for (int j = i; j < system->count - 1; j++) {
        system->passengers[j] = system->passengers[j + 1];
      }
      system->count--;
      printf("Passenger %s removed successfully.\n", passportNumber);
      return;
    }
  }
  printf("Passenger not found.\n");
}

void listPassengers(PassengerSystem *system) {
  if (system->count == 0) {
    printf("No passengers found.\n");
  } else {
    for (int i = 0; i < system->count; i++) {
      Passenger *p = &system->passengers[i];
      printf("Name: %s, Passport: %s, Age: %d, Destination: %s\n", p->name, p->passportNumber, p->age, p->destination);
    }
  }
}

void searchByName(PassengerSystem *system, const char *name) {
  int found = 0;
  for (int i = 0; i < system->count; i++) {
    if (strcasecmp(system->passengers[i].name, name) == 0) {
      printf("Found: Name: %s, Passport: %s, Age: %d, Destination: %s\n",
          system->passengers[i].name,
          system->passengers[i].passportNumber,
          system->passengers[i].age,
          system->passengers[i].destination);
      found = 1;
    }
  }
  if (!found) {
    printf("No passengers found with the name %s.\n", name);
  }
}

void searchByDestination(PassengerSystem *system, const char *destination) {
  int found = 0;
  for (int i = 0; i < system->count; i++) {
    if (strcasecmp(system->passengers[i].destination, destination) == 0) {
      printf("Found: Name: %s, Passport: %s, Age: %d, Destination: %s\n",
          system->passengers[i].name,
          system->passengers[i].passportNumber,
          system->passengers[i].age,
          system->passengers[i].destination);
      found = 1;
    }
  }
  if (!found) {
    printf("No passengers found for destination %s.\n", destination);
  }
}

int compareByName(const void *a, const void *b) {
  return strcmp(((Passenger *)a)->name, ((Passenger *)b)->name);
}

int compareByAge(const void *a, const void *b) {
  return ((Passenger *)a)->age - ((Passenger *)b)->age;
}

void sortPassengers(PassengerSystem *system, int byName) {
  if (byName) {
    qsort(system->passengers, system->count, sizeof(Passenger), compareByName);
    printf("Passengers sorted by name.\n");
  } else {
    qsort(system->passengers, system->count, sizeof(Passenger), compareByAge);
    printf("Passengers sorted by age.\n");
  }
}

void saveToFile(PassengerSystem *system, const char *filename) {
  FILE *file = fopen(filename, "w");
  if (!file) {
    printf("Error opening file for saving.\n");
    return;
  }
  for (int i = 0; i < system->count; i++) {
    Passenger *p = &system->passengers[i];
    fprintf(file, "%s,%s,%d,%s\n", p->name, p->passportNumber, p->age, p->destination);
