void calcul_parallelepipede(double longueur, double largeur, double hauteur, double *volume, double *aire_surface) {
  // Calcul du volume
  *volume = longueur * largeur * hauteur;

  // Calcul de l'aire de la surface
  *aire_surface = 2 * (longueur * largeur + largeur * hauteur + hauteur * longueur);
}

int main() {
