  printf("Entrez la largeur du parallélépipède : ");
  scanf("%lf", &largeur);
  printf("Entrez la hauteur du parallélépipède : ");
  scanf("%lf", &hauteur);

  calcul_parallelepipede(longueur, largeur, hauteur, &volume, &aire_surface);
  printf("Volume du parallélépipède : %.2f\n", volume);
  printf("Aire de la surface du parallélépipède : %.2f\n", aire_surface);

  return 0;
