import matplotlib.pyplot as plt
import numpy as np
from scipy import stats

def calculate_statistics(scores):
  mean = np.mean(scores)
  median = np.median(scores)
  mode = stats.mode(scores).mode[0]
  std_dev = np.std(scores)
  return mean, median, mode, std_dev

def categorize_scores(scores):
  categories = {}
  for score in scores:
    if score >= 90:
      category = 'A'
    elif score >= 80:
      category = 'B'
    elif score >= 70:
      category = 'C'
    elif score >= 60:
      category = 'D'
    else:
      category = 'F'

    if category in categories:
      categories[category] += 1
    else:
      categories[category] = 1
  return categories

def plot_distribution(scores):
  plt.hist(scores, bins=10, alpha=0.7, color='blue', edgecolor='black')
  plt.title("Distribution of Exam Scores")
  plt.xlabel("Scores")
  plt.ylabel("Number of Students")
  plt.axvline(np.mean(scores), color='red', linestyle='dashed', linewidth=1, label='Mean')
  plt.axvline(np.median(scores), color='green', linestyle='dashed', linewidth=1, label='Median')
  plt.legend()
  plt.show()

