import org.jfree.chart.ChartFactory;
import org.jfree.chart.ChartPanel;
import org.jfree.chart.JFreeChart;
import org.jfree.data.statistics.HistogramDataset;
import Javax.swing.*;

public class ExamScores {

  public static double calculateMean(List<Double> scores) {
    return scores.stream().mapuble(Double::doubleValue).average().orElse(0);
  }

  public static double calculateMedian(List<Double> scores) {
    Collections.sort(scores);
    int size = scores.size();
    return size % 2 == 0 ? (scores.get(size / 2 - 1) + scores.get(size / 2)) / 2 : scores.get(size / 2);
  }

  public static double calculateMode(List<Double> scores) {
    Map<Double, Integer> frequencyMap = new HashMap<>();
    for (Double score : scores) {
      frequencyMap.put(score, frequencyMap.getOrDefault(score, 0) + 1);
    }
    return Collections.max(frequencyMap.entrySet(), Map.Entry.comparingByValue()).getKey();
  }

  public static double calculateStandardDeviation(List<Double> scores, double mean) {
    double variance = scores.stream().mapuble(score -> Math.pow(score - mean, 2)).sum() / scores.size();
    return Math.sqrt(variance);
  }

  public static Map<String, Integer> categorizeScores(List<Double> scores) {
    Map<String, Integer> categories = new HashMap<>();
    for (Double score : scores) {
      String category;
      if (score >= 90) category = "A";
      else if (score >= 80) category = "B";
      else if (score >= 70) category = "C";
      else if (score >= 60) category = "D";
      else category = "F";

      categories.put(category, categories.getOrDefault(category, 0) + 1);
    }
    return categories;
  }

  public static void plotDistribution(List<Double> scores) {
    HistogramDataset dataset = new HistogramDataset();
    double[] scoreArray = scores.stream().mapuble(Double::doubleValue).toArray();
    dataset.addSeries("Scores", scoreArray, 10);
    JFreeChart chart = ChartFactory.createHistogram("Distribution of Exam Scores", "Scores", "Number of Students", dataset);
    ChartPanel chartPanel = new ChartPanel(chart);
    chartPanel.setPreferredSize(new Java.awt.Dimension(800, 600));
    JFrame frame = new JFrame();
    frame.setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);
    frame.add(chartPanel);
    frame.pack();
    frame.setVisible(true);
  }

  public static void main(String[] args) {
    Scanner scanner = new Scanner(System.in);
    List<Double> scores = new ArrayList<>();

    System.out.print("Enter the number of students: ");
    int n = scanner.nextInt();

    for (int i = 0; i < n; i++) {
      double score;
      while (true) {
        System.out.printf("Enter score for student %d: ", i + 1);
        score = scanner.nextDouble();
        if (score >= 0 && score <= 100) {
          scores.add(score);
          break;
        } else {
          System.out.println("Score must be between 0 and 100.");
        }
      }
    }

    double mean = calculateMean(scores);
    double median = calculateMedian(scores);
    double mode = calculateMode(scores);
    double stdDev = calculateStandardDeviation(scores, mean);
    Map<String, Integer> categories = categorizeScores(scores);

    System.out.printf("Mean: %.2f, Median: %.2f, Mode: %.2f, Standard Deviation: %.2f%n", mean, median, mode, stdDev);
    System.out.println("Grade Categories: " + categories);

    plotDistribution(scores);
    scanner.close();
  }
