import Java.util.*;

public class SortStudentsByAverage {
  public static double calculateAverage(List<Integer> marks) {
    return marks.stream().mapToInt(Integer::intValue).average().orElse(0.0);
  }

  public static List<Map.Entry<String, Double>> sortStudentsByAverage(Map<String, List<Integer>> students) {
    List<Map.Entry<String, Double>> sortedList = new ArrayList<>();
    for (Map.Entry<String, List<Integer>> entry : students.entrySet()) {
      double average = calculateAverage(entry.getValue());
      sortedList.add(new AbstractMap.SimpleEntry<>(entry.getKey(), average));
    }
    sortedList.sort((e1, e2) -> Double.compare(e2.getValue(), e1.getValue()));
    return sortedList;
  }

  public static void main(String[] args) {
    Map<String, List<Integer>> studentsMarks = new HashMap<>();
    studentsMarks.put("Alice", Arrays.asList(85, 90, 92));
    studentsMarks.put("Bob", Arrays.asList(78, 85, 88));
    studentsMarks.put("Charlie", Arrays.asList(95, 100, 97));

    List<Map.Entry<String, Double>> sortedStudents = sortStudentsByAverage(studentsMarks);
    System.out.println("Students sorted by average marks:");
    for (Map.Entry<String, Double> entry : sortedStudents) {
      System.out.printf("%s: %.2f%n", entry.getKey(), entry.getValue());
    }
  }
