public class VolumeConverter {

  public static double convertVolume(double value, String fromUnit, String toUnit) {
    // Conversion factors
    double[] factors = {1, 10, 100}; // L, dL, cL
    String[] units = {"L", "dL", "cL"};

    int fromIndex = Java.util.Arrays.asList(units).indexOf(fromUnit);
    int toIndex = Java.util.Arrays.asList(units).indexOf(toUnit);

    return value * (factors[fromIndex] / factors[toIndex]);
  }

  public static void main(String[] args) {
    double volume = 5; // in liters
    double volumeDl = convertVolume(volume, "L", "dL");
    double volumeCl = convertVolume(volume, "L", "cL");
    System.out.println(volume + " liters is equal to " + volumeDl + " deciliters and " + volumeCl + " centiliters.");

    double volumeClInput = 500;
    double volumeL = convertVolume(volumeClInput, "cL", "L");
    System.out.println(volumeClInput + " centiliters is equal to " + volumeL + " liters.");
  }
