#include <chrono>
#include <thread>

#define DEFAULT_SIZE 20

void printGrid(const std::vector<std::vector<bool>>& grid) {
  for (const auto& row : grid) {
    for (bool cell : row) {
      std::cout << (cell ? 'O' : '.') << ' ';
    }
    std::cout << '\n';
  }
}

int countNeighbors(const std::vector<std::vector<bool>>& grid, int x, int y) {
  int count = 0;
  for (int i = -1; i <= 1; i++) {
    for (int j = -1; j <= 1; j++) {
      if (i == 0 && j == 0) continue;
      int ni = (x + i + DEFAULT_SIZE) % DEFAULT_SIZE;
      int nj = (y + j + DEFAULT_SIZE) % DEFAULT_SIZE;
      count += grid[ni][nj];
    }
  }
  return count;
}

void updateGrid(std::vector<std::vector<bool>>& grid) {
  std::vector<std::vector<bool>> newGrid(DEFAULT_SIZE, std::vector<bool>(DEFAULT_SIZE));
  for (int i = 0; i < DEFAULT_SIZE; i++) {
    for (int j = 0; j < DEFAULT_SIZE; j++) {
      int total = countNeighbors(grid, i, j);
      if (grid[i][j]) {
        newGrid[i][j] = (total == 2 || total == 3);
      } else {
        newGrid[i][j] = (total == 3);
      }
    }
  }
  grid = newGrid;
}

void saveGrid(const std::vector<std::vector<bool>>& grid, const std::string& filename) {
  std::ofstream file(filename);
  for (const auto& row : grid) {
    for (bool cell : row) {
      file << (cell ? '1' : '0');
    }
    file << '\n';
  }
}

void loadGrid(std::vector<std::vector<bool>>& grid, const std::string& filename) {
  std::ifstream file(filename);
  for (int i = 0; i < DEFAULT_SIZE; i++) {
    for (int j = 0; j < DEFAULT_SIZE; j++) {
      char ch;
      file.get(ch);
      grid[i][j] = (ch == '1');
    }
    file.ignore(); // Ignore the newline character
  }
}

void loadPattern(std::vector<std::vector<bool>>& grid, const std::string& filename) {
  std::ifstream file(filename);
  if (!file) {
    std::cerr << "Pattern file not found!" << std::endl;
    return;
  }
  for (int i = 0; i < DEFAULT_SIZE; i++) {
    for (int j = 0; j < DEFAULT_SIZE; j++) {
      char ch;
      file.get(ch);
      grid[i][j] = (ch == '1');
    }
    file.ignore(); // Ignore the newline character
  }
}

void pauseSimulation(int& delay) {
  std::cout << "Paused. Press any key to continue..." << std::endl;
  _getch(); // Wait for any key
  std::cout << "Resuming..." << std::endl;
}

int main() {
  int size;
  std::cout << "Enter grid size (max " << DEFAULT_SIZE << "): ";
  std::cin >> size;
  if (size > DEFAULT_SIZE) size = DEFAULT_SIZE;

  std::vector<std::vector<bool>> grid(DEFAULT_SIZE, std::vector<bool>(DEFAULT_SIZE));
  srand(time(0));

  // Initialize grid randomly
  for (int i = 0; i < size; i++) {
    for (int j = 0; j < size; j++) {
      grid[i][j] = rand() % 2;
    }
  }

  bool running = true;
  int delay = 200000; // Default delay in microseconds
  while (true) {
    if (_kbhit()) {
      char ch = _getch();
      if (ch == 'p') running = !running; // Pause/Resume
      if (ch == 's') saveGrid(grid, size, "saved_grid.txt"); // Save
      if (ch == 'l') loadGrid(grid, size, "saved_grid.txt"); // Load
      if (ch == '+') delay = (delay > 100000) ? delay - 50000 : delay; // Speed up
      if (ch == '-') delay += 50000; // Slow down
      if (ch == 'g') loadPattern(grid, "glider.txt"); // Load glider
      if (ch == 'q') break; // Quit the simulation
    }
    if (running) {
      printGrid(grid);
      updateGrid(grid);
      usleep(delay);
      std::cout << "\033[H\033[J"; // Clear the console
    } else {
      pauseSimulation(delay);
    }
  }

  return 0;
