  struct Employee* attendees[10]; // New field
  int attendee_count;
};

struct Employee {
  char name[50];
  char position[50];
  double salary;
  double performance_rating; // Default rating
  struct Event events[10];
  int event_count;
};

void display_event(struct Event event) {
  printf("Event: %s, Date: %s, Description: %s, Recurring: %s, Category: %s\n",
      event.title, event.date, event.description, event.is_recurring ? "Yes" : "No", event.category);
}

void display(struct Employee emp) {
  printf("%s: %s, Salary: %.2f, Performance Rating: %.1f\n", emp.position, emp.name, emp.salary, emp.performance_rating);
  printf("Events:\n");
  for (int i = 0; i < emp.event_count; i++) {
    display_event(emp.events[i]);
  }
}

void add_event(struct Employee* emp, struct Event event) {
  for (int i = 0; i < emp->event_count; i++) {
    if (strcmp(emp->events[i].date, event.date) == 0) {
      printf("Conflict detected: %s\n", emp->events[i].title);
      return;
    }
  }
  emp->events[emp->event_count++] = event;
  emp->events[emp->event_count - 1].attendees[emp->events[emp->event_count - 1].attendee_count++] = emp; // Automatically add employee as attendee
}

void notify_upcoming_events(struct Employee emp, const char* current_date) {
  for (int i = 0; i < emp.event_count; i++) {
    if (strcmp(emp.events[i].date, current_date) == 0) {
      printf("Notification: %s, you have an upcoming event: %s\n", emp.name, emp.events[i].title);
    }
  }
}

