class Event {
public:
  std::string title;
  std::string date; // YYYY-MM-DD
  std::string description;
  bool isRecurring;
  std::string category;
  std::set<Employee*> attendees;
  int attendanceCount; // New field for attendance tracking

  Event(std::string t, std::string d, std::string desc, bool recurring = false, std::string cat = "")
    : title(t), date(d), description(desc), isRecurring(recurring), category(cat), attendanceCount(0) {}

  void display() {
    std::cout << "Event: " << title << ", Date: " << date
         << ", Description: " << description
         << ", Recurring: " << (isRecurring ? "Yes" : "No")
         << ", Category: " << category
         << ", Attendance Count: " << attendanceCount << std::endl;
  }

  void mark_attendance(Employee* emp) {
    if (attendees.find(emp) != attendees.end()) {
      attendanceCount++;
    }
  }

  // Other methods...
};

class Department {
public:
  std::string name;
  std::vector<Employee> employees;
  std::vector<Event> proposedEvents; // New list to manage proposed events

  void propose_event(const Event& event) {
    proposedEvents.push_back(event);
    std::cout << "Event proposed: " << event.title << std::endl;
  }

  void approve_event(const Event& event) {
    proposedEvents.erase(std::remove(proposedEvents.begin(), proposedEvents.end(), event), proposedEvents.end());
    for (auto& emp : employees) {
      emp.add_event(event);
    }
    std::cout << "Event approved: " << event.title << std::endl;
  }

  // Other methods...
};

