const int MAXN = 100100;
int a[MAXN], sum[MAXN];

int main() {
  cin.tie(0);
  ios::sync_with_stdio(false);
  int N, K;
  while (cin >> N >> K) {
  	if (N==0 && K==0) break;
  	for (int i = 0; i < N; i++)
  		cin >> a[i];
  	for (int i = 0; i < N; i++) 
  		sum[i+1] = sum[i]+a[i];
  	int ans = -1e9-1;
  	for (int i = 0; i+K <= N; i++) {
  		ans = max(ans, sum[i+K]-sum[i]);
  	}
  	cout << ans << endl;
  }
  return 0;
},0

#include <algorithm>
#include <iostream>

using namespace std;

int main() {
 for (;;) {
  int n, k;
  cin >> n >> k;
  if (!n && !k) return 0;
  int a[n];
  long long result = 0;
  for (int i = 0; i < n; i++) {
   cin >> a[i];
   if (i < k)
    result += a[i];
  }
  long long sum = result;
  for (int i = k; i < n; i++) {
   sum = sum - a[i-k] + a[i];
   result = max(result, sum);
  }
  cout << result << endl;
 }
},0

import Java.util.Arrays;
import Java.util.Scanner;

class Main{



	public static void main(String[] args) {
		Scanner sc = new Scanner(System.in);			//文字の入力
		String string = sc.next();
		char[] cs = string.toCharArray();
		Arrays.sort(cs);
		int count = 1;
		for(int i = 0;i < string.length()-1;i++){
			if(cs[i] == cs[i+1]){
				count++;
			}else{
				if(count%2 != 0){
					System.out.println("No");
					return;
				}
				count = 1;
			}
		}
		if(count%2 != 0){
			System.out.println("No");
			return;
		}else{
			System.out.println("Yes");
		}

	}
},0

package queues;

import java.util.LinkedList;
import java.util.Scanner;

public class QueueUsingTwoStacks {

    private static Scanner in = new Scanner(System.in);

    public static void main(String[] args) {
        int queries = in.nextInt();
        performQueries(queries);
    }

    private static void performQueries(int queries){
        LinkedList<Integer> linkedList = new LinkedList<>();

        while (queries-- > 0){
            int type = in.nextInt();
            if(type == 1){
                int data = in.nextInt();
                linkedList.add(data);
            } else if(type == 2){
                linkedList.pop();
            } else {
                System.out.println(linkedList.peek());
            }
        }
    }
}
