#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main() {
  char word[100];
  int length, isPalindrome = 1;

  printf("Enter a word: ");
  scanf("%s", word);

  length = strlen(word);
  for (int i = 0; i < length / 2; i++) {
    if (tolower(word[i]) != tolower(word[length - i - 1])) {
      isPalindrome = 0;
      break;
    }
  }

  if (isPalindrome) {
    printf("%s is a palindrome.\n", word);
  } else {
    printf("%s is not a palindrome.\n", word);
  }

  return 0;
},1
